local http = require "resty.http"
local httpc = http.new()

local function is_private_ip(ip)
    if not ip then return true end
    
    local patterns = {
        "^127%.",
        "^10%.",
        "^172%.1[6-9]%.",
        "^172%.2[0-9]%.",
        "^172%.3[0-1]%.",
        "^192%.168%.",
        "^169%.254%.",
        "^::1$",
        "^[fF][cCdD]",
        "^[fF][eE]80:",
        "^0:",
        "^localhost$"
    }
    
    for _, pattern in ipairs(patterns) do
        if string.match(ip, pattern) then
            return true
        end
    end
    
    return false
end

local function validate_url(url)
    if not url or url == "" then
        return false, "URL is required"
    end
    
    if #url > 2048 then
        return false, "URL too long"
    end
    
    local scheme = string.match(url, "^([^:]+)://")
    if scheme ~= "http" and scheme ~= "https" then
        return false, "Only HTTP and HTTPS schemes are allowed"
    end
    
    local host = string.match(url, "^https?://([^/:]+)")
    if not host then
        return false, "Invalid URL format"
    end
    
    if string.match(host, "^%d+%.%d+%.%d+%.%d+$") then
        if is_private_ip(host) then
            return false, "Access to private IP addresses is forbidden"
        end
    end
    
    local resolver = require "resty.dns.resolver"
    local r, err = resolver:new{
        nameservers = {"8.8.8.8", "8.8.4.4"},
        retrans = 2,
        timeout = 1000,
    }
    
    if not r then
        return false, "Failed to initialize DNS resolver"
    end
    
    local answers, err = r:query(host, {qtype = r.TYPE_A})
    if not answers or answers.errcode then
        answers, err = r:query(host, {qtype = r.TYPE_AAAA})
    end
    
    if answers and not answers.errcode then
        for _, ans in ipairs(answers) do
            if ans.address and is_private_ip(ans.address) then
                return false, "Domain resolves to private IP address"
            end
        end
    end
    
    return true, nil
end

local target_url = ngx.var.arg_url

local valid, err = validate_url(target_url)
if not valid then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say('{"error": "', err, '"}')
    return ngx.exit(ngx.HTTP_BAD_REQUEST)
end

httpc:set_timeouts(5000, 5000, 5000)

local res, err = httpc:request_uri(target_url, {
    method = ngx.var.request_method,
    ssl_verify = true,
    keepalive_timeout = 60000,
    keepalive_pool = 10,
    headers = {
        ["User-Agent"] = "OpenResty-Webhook-Forwarder/1.0"
    }
})

if not res then
    ngx.status = ngx.HTTP_BAD_GATEWAY
    ngx.say('{"error": "Failed to fetch URL: ', err, '"}')
    return ngx.exit(ngx.HTTP_BAD_GATEWAY)
end

if res.status >= 300 and res.status < 400 then
    local location = res.headers["Location"]
    if location then
        local redirect_valid, redirect_err = validate_url(location)
        if not redirect_valid then
            ngx.status = ngx.HTTP_FORBIDDEN
            ngx.say('{"error": "Redirect blocked: ', redirect_err, '"}')
            return ngx.exit(ngx.HTTP_FORBIDDEN)
        end
    end
end

ngx.status = res.status

for k, v in pairs(res.headers) do
    if k ~= "Transfer-Encoding" and k ~= "Connection" then
        ngx.header[k] = v
    end
end

ngx.say(res.body)